import React, { useEffect, useRef, useState } from 'react';
import {
  Stage,
  Layer,
  Group,
  Image as KonvaImage,
  Rect,
  Line,
  Circle,
  Ellipse,
  Arrow,
} from 'react-konva';
import './AnnotationCanvas.css';

export default function AnnotationCanvas({
  fileUrl,
  annotations,
  onAnnotationsChange,
  selectedTool,
  scale,
  onWheelZoom,
  activeLabelColor,
  onFinishShape,
}) {
  const stageRef = useRef(null);
  const containerRef = useRef(null);

  const [dims, setDims] = useState({ width: 0, height: 0 });
  const [konvaImg, setKonvaImg] = useState(null);
  const [imagePos, setImagePos] = useState({ x: 0, y: 0 });

  // In-progress shape states
  const [newBox, setNewBox] = useState(null);
  const [tempPoints, setTempPoints] = useState([]);
  const [drawingPolygon, setDrawingPolygon] = useState(false);
  const [tempPolyline, setTempPolyline] = useState([]);
  const [drawingPolyline, setDrawingPolyline] = useState(false);
  const [newEllipse, setNewEllipse] = useState(null);

  // -------------- Setup --------------
  useEffect(() => {
    const handleResize = () => {
      if (!containerRef.current) return;
      setDims({
        width: containerRef.current.offsetWidth,
        height: containerRef.current.offsetHeight,
      });
    };
    window.addEventListener('resize', handleResize);
    handleResize();
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Load image
  useEffect(() => {
    if (!fileUrl) return;
    const img = new window.Image();
    img.src = fileUrl;
    img.onload = () => {
      setKonvaImg(img);
      setImagePos({ x: 0, y: 0 });
    };
    img.onerror = () => console.error('Could not load image:', fileUrl);
  }, [fileUrl]);

  const getGroupPos = (evt) => {
    const group = stageRef.current?.findOne('#anno-group');
    return group ? group.getRelativePointerPosition() : null;
  };

  const flattenPoints = (pts) => pts.flatMap((p) => [p.x, p.y]);

  // shapeBoundingBox + isOutsideImage => used for checking out-of-bounds
  function shapeBoundingBox(ann) {
    if (ann.type === 'bbox') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x + ann.width,
        y2: ann.y + ann.height,
      };
    } else if (ann.type === 'ellipse') {
      return {
        x1: ann.x - ann.radiusX,
        y1: ann.y - ann.radiusY,
        x2: ann.x + ann.radiusX,
        y2: ann.y + ann.radiusY,
      };
    } else if (ann.type === 'polygon' || ann.type === 'polyline') {
      let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
      ann.points.forEach((pt) => {
        if (pt.x < minX) minX = pt.x;
        if (pt.y < minY) minY = pt.y;
        if (pt.x > maxX) maxX = pt.x;
        if (pt.y > maxY) maxY = pt.y;
      });
      return { x1: minX, y1: minY, x2: maxX, y2: maxY };
    } else if (ann.type === 'point') {
      return {
        x1: ann.x,
        y1: ann.y,
        x2: ann.x,
        y2: ann.y,
      };
    }
    return null;
  }
  function isOutsideImage(ann) {
    if (!konvaImg) return false;
    const { x1, y1, x2, y2 } = shapeBoundingBox(ann);
    if (x2 < 0 || x1 > konvaImg.width || y2 < 0 || y1 > konvaImg.height) {
      return true;
    }
    return false;
  }

  // -------------- BBox creation --------------
  function startBox(pos) {
    setNewBox({ x: pos.x, y: pos.y, width: 0, height: 0 });
  }
  function updateBox(pos) {
    if (!newBox) return;
    setNewBox({
      ...newBox,
      width: pos.x - newBox.x,
      height: pos.y - newBox.y,
    });
  }
  function finalizeBox() {
    if (!newBox) return;
    const newAnn = { type: 'bbox', ...newBox, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    setNewBox(null);
    onFinishShape && onFinishShape();
  }

  // -------------- Polygon creation --------------
  function addPolygonPoint(pos) {
    setTempPoints((prev) => [...prev, pos]);
    setDrawingPolygon(true);
  }
  function finalizePolygon() {
    if (tempPoints.length >= 3) {
      const newAnn = { type: 'polygon', points: tempPoints, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPoints([]);
    setDrawingPolygon(false);
    onFinishShape && onFinishShape();
  }

  // -------------- Polyline creation --------------
  function addPolylinePoint(pos) {
    setTempPolyline((prev) => [...prev, pos]);
    setDrawingPolyline(true);
  }
  function finalizePolyline() {
    if (tempPolyline.length >= 2) {
      const newAnn = { type: 'polyline', points: tempPolyline, label: '' };
      if (!isOutsideImage(newAnn)) {
        onAnnotationsChange([...annotations, newAnn]);
      }
    }
    setTempPolyline([]);
    setDrawingPolyline(false);
    onFinishShape && onFinishShape();
  }

  // -------------- Point creation --------------
  function addPoint(pos) {
    const newAnn = { type: 'point', x: pos.x, y: pos.y, label: '' };
    if (!isOutsideImage(newAnn)) {
      onAnnotationsChange([...annotations, newAnn]);
    }
    onFinishShape && onFinishShape();
  }

  // -------------- Ellipse creation --------------
  function startEllipse(pos) {
    setNewEllipse({
      type: 'ellipse',
      x: pos.x,
      y: pos.y,
      radiusX: 0,
      radiusY: 0,
      rotation: 0,
      label: '',
    });
  }
  function updateEllipse(pos) {
    if (!newEllipse) return;
    const rx = Math.abs(pos.x - newEllipse.x);
    const ry = Math.abs(pos.y - newEllipse.y);
    setNewEllipse({
      ...newEllipse,
      radiusX: rx,
      radiusY: ry,
    });
  }
  function finalizeEllipse() {
    if (!newEllipse) return;
    if (!isOutsideImage(newEllipse)) {
      onAnnotationsChange([...annotations, { ...newEllipse }]);
    }
    setNewEllipse(null);
    onFinishShape && onFinishShape();
  }

  // -------------- Mouse / DoubleClick --------------
  const handleMouseDown = (evt) => {
    if (selectedTool === 'move') return; // panning if empty space
    const pos = getGroupPos(evt);
    if (!pos) return;

    if (selectedTool === 'bbox') {
      startBox(pos);
    } else if (selectedTool === 'polygon') {
      addPolygonPoint(pos);
    } else if (selectedTool === 'polyline') {
      addPolylinePoint(pos);
    } else if (selectedTool === 'point') {
      addPoint(pos);
    } else if (selectedTool === 'ellipse') {
      startEllipse(pos);
    }
  };
  const handleMouseMove = (evt) => {
    if (selectedTool === 'bbox' && newBox) {
      const pos = getGroupPos(evt);
      if (pos) updateBox(pos);
    } else if (selectedTool === 'ellipse' && newEllipse) {
      const pos = getGroupPos(evt);
      if (pos) updateEllipse(pos);
    }
  };
  const handleMouseUp = () => {
    if (selectedTool === 'bbox' && newBox) {
      finalizeBox();
    } else if (selectedTool === 'ellipse' && newEllipse) {
      finalizeEllipse();
    }
  };
  const handleDblClick = () => {
    if (selectedTool === 'polygon' && drawingPolygon) {
      finalizePolygon();
    } else if (selectedTool === 'polyline' && drawingPolyline) {
      finalizePolyline();
    }
  };

  // -------------- ESC => cancel shape --------------
  useEffect(() => {
    const onCancelAnnotation = () => {
      setNewBox(null);
      setTempPoints([]);
      setDrawingPolygon(false);
      setTempPolyline([]);
      setDrawingPolyline(false);
      setNewEllipse(null);
    };
    window.addEventListener('cancel-annotation', onCancelAnnotation);
    return () => window.removeEventListener('cancel-annotation', onCancelAnnotation);
  }, []);

  // -------------- Wheel Zoom --------------
  const handleWheel = (evt) => {
    evt.evt.preventDefault();
    onWheelZoom(evt.evt.deltaY);
  };

  // -------------- Sub-Components --------------

  /**
   * BBoxWithHandles:
   * - Entire bounding box can be dragged by clicking inside the rectangle.
   * - 4 corner handles (top-left, top-right, bottom-left, bottom-right) for resizing.
   */
  function BBoxWithHandles({ ann, index }) {
    const [hovered, setHovered] = useState(false); // if you want to show handles only on hover
    const groupRef = useRef(null);

    const { x, y, width, height } = ann;

    // Move entire box
    const handleDragStart = (e) => {
      e.cancelBubble = true;
    };
    const handleDragMove = (e) => {
      e.cancelBubble = true;
    };
    const handleDragEnd = (e) => {
      e.cancelBubble = true;
      const { x: newX, y: newY } = e.target.position();
      const updated = [...annotations];
      updated[index] = { ...ann, x: newX, y: newY };
      if (isOutsideImage(updated[index])) {
        updated.splice(index, 1);
      }
      onAnnotationsChange(updated);
      // reset group offset
      e.target.position({ x: newX, y: newY });
    };

    // Handle for resizing corners
    // cornerName in { "tl", "tr", "bl", "br" }
    const handleCornerDragMove = (cornerName, e2) => {
      e2.cancelBubble = true;
      const { x: cx, y: cy } = e2.target.position();

      let newX = ann.x;
      let newY = ann.y;
      let newW = ann.width;
      let newH = ann.height;
      const rightX = ann.x + ann.width;
      const bottomY = ann.y + ann.height;

      // logic for each corner
      if (cornerName === 'tl') {
        // top-left corner
        newX = cx;
        newY = cy;
        newW = rightX - newX;
        newH = bottomY - newY;
      } else if (cornerName === 'tr') {
        // top-right corner
        newY = cy;
        newW = cx - ann.x;
        newH = bottomY - newY;
      } else if (cornerName === 'bl') {
        // bottom-left corner
        newX = cx;
        newW = rightX - newX;
        newH = cy - ann.y;
      } else if (cornerName === 'br') {
        // bottom-right corner
        newW = cx - ann.x;
        newH = cy - ann.y;
      }
      // handle negative width/height => flip
      if (newW < 0) {
        newX = newX + newW;
        newW = Math.abs(newW);
      }
      if (newH < 0) {
        newY = newY + newH;
        newH = Math.abs(newH);
      }

      const updated = [...annotations];
      updated[index] = { ...ann, x: newX, y: newY, width: newW, height: newH };
      onAnnotationsChange(updated);
    };

    // corner positions
    const tlPos = { x: x, y: y };
    const trPos = { x: x + width, y: y };
    const blPos = { x: x, y: y + height };
    const brPos = { x: x + width, y: y + height };

    const circleRadius = 6 / scale;

    return (
      <Group
        ref={groupRef}
        // position the group at (0,0) then the Rect is at (ann.x, ann.y)
        // or we can do the group at (ann.x, ann.y), then the rect is at (0,0)
        // But simpler to keep the shape coords as is:
        draggable
        onDragStart={handleDragStart}
        onDragMove={handleDragMove}
        onDragEnd={handleDragEnd}
        x={x}
        y={y}
        onMouseEnter={() => setHovered(true)}
        onMouseLeave={() => setHovered(false)}
      >
        {/* The main rectangle.  We'll draw it at (0,0) with width, height. 
            Because the group is at (x,y). */}
        <Rect
          x={0}
          y={0}
          width={width}
          height={height}
          fill={activeLabelColor + '55'}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          onMouseDown={(e) => e.cancelBubble = true}
          onDragMove={(e) => e.cancelBubble = true}
        />

        {/* Show handles if hovered, or always if you prefer */}
        {(hovered || true) && (
          <>
            {/* top-left */}
            <Circle
              x={0} // relative to group
              y={0}
              radius={circleRadius}
              fill="#fff"
              stroke={activeLabelColor}
              strokeWidth={2 / scale}
              draggable
              onMouseDown={(e) => e.cancelBubble = true}
              onDragMove={(e) => handleCornerDragMove('tl', e)}
            />
            {/* top-right */}
            <Circle
              x={width}
              y={0}
              radius={circleRadius}
              fill="#fff"
              stroke={activeLabelColor}
              strokeWidth={2 / scale}
              draggable
              onMouseDown={(e) => e.cancelBubble = true}
              onDragMove={(e) => handleCornerDragMove('tr', e)}
            />
            {/* bottom-left */}
            <Circle
              x={0}
              y={height}
              radius={circleRadius}
              fill="#fff"
              stroke={activeLabelColor}
              strokeWidth={2 / scale}
              draggable
              onMouseDown={(e) => e.cancelBubble = true}
              onDragMove={(e) => handleCornerDragMove('bl', e)}
            />
            {/* bottom-right */}
            <Circle
              x={width}
              y={height}
              radius={circleRadius}
              fill="#fff"
              stroke={activeLabelColor}
              strokeWidth={2 / scale}
              draggable
              onMouseDown={(e) => e.cancelBubble = true}
              onDragMove={(e) => handleCornerDragMove('br', e)}
            />
          </>
        )}
      </Group>
    );
  }

  /**
   * EllipseWithHandles:
   * - Draggable ellipse (move entire ellipse).
   * - 4 handles at cardinal directions for radiusX, radiusY changes.
   */
  function EllipseWithHandles({ ann, index }) {
    const [hovered, setHovered] = useState(false);
    const groupRef = useRef(null);

    const { x, y, radiusX, radiusY, rotation = 0 } = ann;

    // Move entire ellipse
    const handleDragStart = (e) => e.cancelBubble = true;
    const handleDragMove = (e) => e.cancelBubble = true;
    const handleDragEnd = (e) => {
      e.cancelBubble = true;
      const gx = e.target.x();
      const gy = e.target.y();
      const updated = [...annotations];
      updated[index] = { ...ann, x: gx, y: gy };
      if (isOutsideImage(updated[index])) {
        updated.splice(index, 1);
      }
      onAnnotationsChange(updated);
    };

    // For cardinal handles: left, right, top, bottom => manipulate radiusX, radiusY
    const handleEllipseHandleDragMove = (handleType, e2) => {
      e2.cancelBubble = true;
      // The group is at (x, y), so handle's position is relative
      // If the group is at (x, y), the ellipse is at (0,0).
      const { x: hx, y: hy } = e2.target.position();

      let newRx = radiusX;
      let newRy = radiusY;

      if (handleType === 'right') {
        // hx is the new radiusX
        newRx = Math.abs(hx);
      } else if (handleType === 'left') {
        // hx is negative radius
        newRx = Math.abs(hx);
      } else if (handleType === 'top') {
        // hy is negative radius
        newRy = Math.abs(hy);
      } else if (handleType === 'bottom') {
        // hy is positive radius
        newRy = Math.abs(hy);
      }

      const updated = [...annotations];
      updated[index] = {
        ...ann,
        radiusX: newRx,
        radiusY: newRy,
      };
      onAnnotationsChange(updated);
    };

    const circleRadius = 6 / scale;

    return (
      <Group
        ref={groupRef}
        x={x}
        y={y}
        draggable
        onDragStart={handleDragStart}
        onDragMove={handleDragMove}
        onDragEnd={handleDragEnd}
        onMouseEnter={() => setHovered(true)}
        onMouseLeave={() => setHovered(false)}
      >
        {/* Ellipse at (0,0) with radiusX, radiusY */}
        <Ellipse
          x={0}
          y={0}
          radiusX={radiusX}
          radiusY={radiusY}
          rotation={rotation}
          fill={activeLabelColor + '55'}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          onMouseDown={(e) => e.cancelBubble = true}
        />

        {/* 4 handles at cardinal directions, if hovered or always if you want */}
        {(hovered || true) && (
          <>
            {/* Right handle => ( radiusX, 0 ) */}
            <Circle
              x={radiusX}
              y={0}
              radius={circleRadius}
              fill="#fff"
              stroke={activeLabelColor}
              strokeWidth={2 / scale}
              draggable
              onMouseDown={(e) => e.cancelBubble = true}
              onDragMove={(e) => handleEllipseHandleDragMove('right', e)}
            />
            {/* Left handle => ( -radiusX, 0 ) */}
            <Circle
              x={-radiusX}
              y={0}
              radius={circleRadius}
              fill="#fff"
              stroke={activeLabelColor}
              strokeWidth={2 / scale}
              draggable
              onMouseDown={(e) => e.cancelBubble = true}
              onDragMove={(e) => handleEllipseHandleDragMove('left', e)}
            />
            {/* Top handle => ( 0, -radiusY ) */}
            <Circle
              x={0}
              y={-radiusY}
              radius={circleRadius}
              fill="#fff"
              stroke={activeLabelColor}
              strokeWidth={2 / scale}
              draggable
              onMouseDown={(e) => e.cancelBubble = true}
              onDragMove={(e) => handleEllipseHandleDragMove('top', e)}
            />
            {/* Bottom handle => ( 0, radiusY ) */}
            <Circle
              x={0}
              y={radiusY}
              radius={circleRadius}
              fill="#fff"
              stroke={activeLabelColor}
              strokeWidth={2 / scale}
              draggable
              onMouseDown={(e) => e.cancelBubble = true}
              onDragMove={(e) => handleEllipseHandleDragMove('bottom', e)}
            />
          </>
        )}
      </Group>
    );
  }

  // Polygons & Polylines remain the same as before
  function DraggablePolygon({ ann, index }) {
    const groupRef = useRef(null);

    const handleGroupDragStart = (e) => {
      e.cancelBubble = true;
    };
    const handleGroupDragMove = (e) => {
      e.cancelBubble = true;
    };
    const handleGroupDragEnd = (e) => {
      e.cancelBubble = true;
      const { x, y } = e.target.position();
      const newPoints = ann.points.map((pt) => ({
        x: pt.x + x,
        y: pt.y + y,
      }));
      const updated = [...annotations];
      updated[index] = { ...ann, points: newPoints };
      e.target.position({ x: 0, y: 0 });
      if (isOutsideImage(updated[index])) {
        updated.splice(index, 1);
      }
      onAnnotationsChange(updated);
    };

    const pts = flattenPoints(ann.points);
    const firstPt = ann.points[0];
    const secondPt = ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };

    return (
      <Group
        draggable
        ref={groupRef}
        onDragStart={handleGroupDragStart}
        onDragMove={handleGroupDragMove}
        onDragEnd={handleGroupDragEnd}
        onMouseDown={(e) => e.cancelBubble = true}
      >
        <Line
          points={pts}
          fill={activeLabelColor + '55'}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          closed
        />
        <Arrow
          points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
          fill={activeLabelColor}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          pointerLength={10 / scale}
          pointerWidth={8 / scale}
        />
      </Group>
    );
  }
  function DraggablePolyline({ ann, index }) {
    const groupRef = useRef(null);

    const handleGroupDragStart = (e) => {
      e.cancelBubble = true;
    };
    const handleGroupDragMove = (e) => {
      e.cancelBubble = true;
    };
    const handleGroupDragEnd = (e) => {
      e.cancelBubble = true;
      const { x, y } = e.target.position();
      const newPoints = ann.points.map((pt) => ({
        x: pt.x + x,
        y: pt.y + y,
      }));
      const updated = [...annotations];
      updated[index] = { ...ann, points: newPoints };
      e.target.position({ x: 0, y: 0 });
      if (isOutsideImage(updated[index])) {
        updated.splice(index, 1);
      }
      onAnnotationsChange(updated);
    };

    const pts = flattenPoints(ann.points);
    const firstPt = ann.points[0];
    const secondPt = ann.points[1] || { x: firstPt.x + 10, y: firstPt.y };

    return (
      <Group
        draggable
        ref={groupRef}
        onDragStart={handleGroupDragStart}
        onDragMove={handleGroupDragMove}
        onDragEnd={handleGroupDragEnd}
        onMouseDown={(e) => e.cancelBubble = true}
      >
        <Line
          points={pts}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          closed={false}
        />
        <Arrow
          points={[secondPt.x, secondPt.y, firstPt.x, firstPt.y]}
          fill={activeLabelColor}
          stroke={activeLabelColor}
          strokeWidth={2 / scale}
          pointerLength={10 / scale}
          pointerWidth={8 / scale}
        />
      </Group>
    );
  }

  // Simple circle for point annotations (no handles)
  function DraggablePoint({ ann, index }) {
    const handleDragMove = (e) => {
      e.cancelBubble = true;
    };
    const handleDragEnd = (e) => {
      e.cancelBubble = true;
      const { x, y } = e.target.position();
      const updated = [...annotations];
      updated[index] = { ...ann, x, y };
      if (isOutsideImage(updated[index])) {
        updated.splice(index, 1);
      }
      onAnnotationsChange(updated);
    };
    return (
      <Circle
        x={ann.x}
        y={ann.y}
        radius={6 / scale}
        fill={activeLabelColor}
        draggable
        onMouseDown={(e) => e.cancelBubble = true}
        onDragMove={handleDragMove}
        onDragEnd={handleDragEnd}
      />
    );
  }

  const fillColor = activeLabelColor + '55';

  return (
    <div className="canvas-container" ref={containerRef}>
      <Stage
        ref={stageRef}
        width={dims.width}
        height={dims.height}
        scaleX={scale}
        scaleY={scale}
        style={{ background: '#dfe6e9' }}
        onWheel={handleWheel}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUp}
        onDblClick={handleDblClick}
      >
        <Layer>
          <Group
            id="anno-group"
            draggable={selectedTool === 'move'}
            x={imagePos.x}
            y={imagePos.y}
            onDragEnd={(e) => {
              setImagePos({ x: e.target.x(), y: e.target.y() });
            }}
          >
            {konvaImg && (
              <KonvaImage
                image={konvaImg}
                width={konvaImg.width}
                height={konvaImg.height}
              />
            )}

            {/* Render existing annotations */}
            {annotations.map((ann, i) => {
              if (ann.type === 'bbox') {
                return (
                  <BBoxWithHandles
                    key={i}
                    ann={ann}
                    index={i}
                  />
                );
              } else if (ann.type === 'ellipse') {
                return (
                  <EllipseWithHandles
                    key={i}
                    ann={ann}
                    index={i}
                  />
                );
              } else if (ann.type === 'point') {
                return (
                  <DraggablePoint
                    key={i}
                    ann={ann}
                    index={i}
                  />
                );
              } else if (ann.type === 'polygon') {
                return (
                  <DraggablePolygon
                    key={i}
                    ann={ann}
                    index={i}
                  />
                );
              } else if (ann.type === 'polyline') {
                return (
                  <DraggablePolyline
                    key={i}
                    ann={ann}
                    index={i}
                  />
                );
              }
              return null;
            })}

            {/* In-progress shapes */}
            {newBox && selectedTool === 'bbox' && (
              <Rect
                x={newBox.x}
                y={newBox.y}
                width={newBox.width}
                height={newBox.height}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}
            {drawingPolygon && tempPoints.length > 1 && selectedTool === 'polygon' && (
              <Line
                points={flattenPoints([...tempPoints, tempPoints[0]])}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
                closed
              />
            )}
            {drawingPolyline && tempPolyline.length > 1 && selectedTool === 'polyline' && (
              <Line
                points={flattenPoints(tempPolyline)}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
                closed={false}
              />
            )}
            {newEllipse && selectedTool === 'ellipse' && (
              <Ellipse
                x={newEllipse.x}
                y={newEllipse.y}
                radiusX={newEllipse.radiusX}
                radiusY={newEllipse.radiusY}
                rotation={0}
                fill={fillColor}
                stroke={activeLabelColor}
                strokeWidth={2 / scale}
              />
            )}
          </Group>
        </Layer>
      </Stage>
    </div>
  );
}
